// isASCII checks if a string contains only ASCII characters.
func isASCII(s string) bool {
	for _, r := range s {
		if r > 127 {
			return false
		}
	}
	return true
}

// encodeHeaderName encodes a name for use in email headers (From/To fields)
// handling both ASCII and non-ASCII names properly per RFC 2047.
func encodeHeaderName(name, address string) string {
	if name == "" {
		return address
	}

	var encodedName string
	if isASCII(name) {
		// Quote the name if it contains special characters requiring quoting
		if strings.ContainsAny(name, `",<>()[];:@\`) {
			escapedName := strings.ReplaceAll(name, `"`, `\"`)
			encodedName = fmt.Sprintf(`"%s"`, escapedName)
		} else {
			encodedName = name
		}
	} else {
		// Encode non-ASCII name using quoted-printable encoding
		encodedName = mime.QEncoding.Encode("UTF-8", name)
	}

	return fmt.Sprintf("%s <%s>", encodedName, address)
}

// encodeSubject encodes an email subject to be RFC 2047 compliant, handling non-ASCII characters.
func encodeSubject(subject string) string {
	if isASCII(subject) {
		return subject
	}
	return mime.QEncoding.Encode("UTF-8", subject)
}

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
