	// Basic validation of required fields
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email address formats
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Encode From header with user's name (handles non-ASCII and special characters)
	fromHeader := encodeHeaderName(userName, fromAddr)

	// Construct and encode subject line
	baseSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := encodeSubject(baseSubject)

	// Build email headers with proper RFC 5322 formatting
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromHeader,
		toAddr,
		encodedSubject,
	)

	// Escape user input to prevent XSS attacks and broken HTML markup
