// BuildFeedbackEmail constructs a complete HTML email message for user feedback
// Returns the full MIME email message (headers + body) or an error if validation fails
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Validate required input fields
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("feedback subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	// Encode subject to handle non-ASCII characters per RFC 2047
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Process feedback content: escape HTML entities and preserve line breaks
	escapedContent := template.HTMLEscapeString(feedbackContent)
	formattedContent := strings.ReplaceAll(escapedContent, "\r\n", "<br>")
	formattedContent = strings.ReplaceAll(formattedContent, "\n", "<br>")

	// Prepare data for template execution
	data := emailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: template.HTML(formattedContent),
		Timestamp:       time.Now().UTC().Format(time.RFC3339),
	}

	// Parse and execute the HTML template
	tpl, err := template.New("feedbackEmail").Parse(feedbackEmailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse feedback template: %w", err)
	}

	var htmlBody strings.Builder
	if err := tpl.Execute(&htmlBody, data); err != nil {
		return "", fmt.Errorf("failed to generate HTML body: %w", err)
	}

	// Construct full email message with proper MIME headers
	var emailMsg strings.Builder
	emailMsg.WriteString(fmt.Sprintf("MIME-Version: 1.0\r\n"))
	emailMsg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	emailMsg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	emailMsg.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	emailMsg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	emailMsg.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	// Blank line separates headers from body (required by SMTP standard)
	emailMsg.WriteString("\r\n")
	emailMsg.WriteString(htmlBody.String())

	return emailMsg.String(), nil
