// encodeRFC2047Subject encodes a subject string using RFC 2047 encoded-word format
// to handle non-ASCII characters properly in email headers
func encodeRFC2047Subject(subject string) (string, error) {
	// Check if subject contains only ASCII characters
	allASCII := true
	for _, r := range subject {
		if r > 127 {
			allASCII = false
			break
		}
	}
	if allASCII {
		return subject, nil
	}

	var buf bytes.Buffer
	encoder := quotedprintable.NewWriter(&buf)
	_, err := encoder.Write([]byte(subject))
	if err != nil {
		return "", fmt.Errorf("failed to write subject to encoder: %w", err)
	}
	if err := encoder.Close(); err != nil {
		return "", fmt.Errorf("failed to close encoder: %w", err)
	}

	encoded := buf.String()
	// Replace spaces with =20 as required by RFC 2047 for quoted-printable
	encoded = strings.ReplaceAll(encoded, " ", "=20")
	// Remove any line breaks inserted by the quoted-printable encoder
	encoded = strings.ReplaceAll(encoded, "\r\n", "")
	encoded = strings.ReplaceAll(encoded, "\n", "")

	// Wrap in RFC 2047 encoded-word format
	return fmt.Sprintf("=?UTF-8?Q?%s?=", encoded), nil
}

