// BuildFeedbackEmail generates an HTML-formatted email for user feedback, ready to be sent via SMTP.
// Returns the full email body (including headers and HTML content) and any error encountered during generation.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Escape user-provided content to prevent HTML injection attacks
	userNameEscaped := html.EscapeString(userName)
	subjectEscaped := html.EscapeString(subject)
	feedbackContentEscaped := html.EscapeString(feedbackContent)

	// Encode subject using RFC 2047 to handle non-ASCII characters properly
	subjectEncoded := mime.QEncoding.Encode("UTF-8", subject)

	// Construct email headers required for SMTP delivery and HTML content
	headers := []string{
		fmt.Sprintf("From: %s", fromAddr),
		fmt.Sprintf("To: %s", toAddr),
		fmt.Sprintf("Subject: %s", subjectEncoded),
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=\"UTF-8\"",
	}
	headerStr := strings.Join(headers, "\r\n")

	// Prepare data for template execution
	type templateData struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}
	data := templateData{
		UserName:        userNameEscaped,
		Subject:         subjectEscaped,
		FeedbackContent: feedbackContentEscaped,
	}

	// Parse and execute the HTML template
	tpl, err := template.New("feedbackEmail").Parse(feedbackTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse feedback template: %w", err)
	}

	var htmlBody bytes.Buffer
	if err := tpl.Execute(&htmlBody, data); err != nil {
		return "", fmt.Errorf("failed to generate HTML email body: %w", err)
	}

	// Combine headers and body into the full email string (CRLF separators per RFC 5322)
	fullEmail := fmt.Sprintf("%s\r\n\r\n%s", headerStr, htmlBody.String())

	return fullEmail, nil
}

