var tpl *template.Template

func init() {
	var err error
	tpl, err = template.New("feedbackEmail").Parse(feedbackTemplate)
	if err != nil {
		panic(fmt.Sprintf("failed to parse feedback template: %v", err))
	}
}

type feedbackTemplateData struct {
	UserName        string
	Subject         string
	FeedbackContent string
	SubmittedAt     string
}

// BuildFeedbackEmail generates a complete HTML-formatted email message (headers + body)
// ready to be sent via SMTP. It includes all user feedback information in both headers and body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailMsg string, err error) {
	// Validate required input fields
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("feedback subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	// Parse and validate from address
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}

	// Parse and validate to address
	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Encode user name for RFC 2047 compliance (handles non-ASCII characters)
	encodedUserName := mime.QEncoding.Encode("UTF-8", userName)
	fromHeader := fmt.Sprintf("%s <%s>", encodedUserName, parsedFrom.Address)

	// Encode subject for RFC 2047 compliance
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Prepare template data with current timestamp
	currentTime := time.Now()
	data := feedbackTemplateData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
		SubmittedAt:     currentTime.Format("2006-01-02 15:04:05 MST"),
	}

	// Render HTML body from template
	var htmlBuf bytes.Buffer
	if err := tpl.Execute(&htmlBuf, data); err != nil {
		return "", fmt.Errorf("failed to render feedback template: %w", err)
	}
	htmlBody := htmlBuf.String()

	// Replace LF with CRLF for RFC 5322 compliance
	htmlBodyCRLF := strings.ReplaceAll(htmlBody, "\n", "\r\n")

	// Build full email message with headers
	var msgBuf bytes.Buffer
	fmt.Fprintf(&msgBuf, "From: %s\r\n", fromHeader)
	fmt.Fprintf(&msgBuf, "To: %s\r\n", parsedTo.String())
	fmt.Fprintf(&msgBuf, "Subject: %s\r\n", encodedSubject)
	fmt.Fprintf(&msgBuf, "Date: %s\r\n", currentTime.Format(time.RFC1123Z))
	fmt.Fprintf(&msgBuf, "MIME-Version: 1.0\r\n")
	fmt.Fprintf(&msgBuf, "Content-Type: text/html; charset=UTF-8\r\n")
	fmt.Fprintf(&msgBuf, "\r\n") // Separator between headers and body
	fmt.Fprint(&msgBuf, htmlBodyCRLF)

	return msgBuf.String(), nil
}

func main() {
	// Example usage of BuildFeedbackEmail
	fromAddr := "user@example.com"
	toAddr := "support@example.com"
	userName := "John Doe"
	subject := "Issue with Account Login"
	feedbackContent := `I'm having trouble logging into my account after resetting my password. 
The system displays an "Invalid credentials" error even though I'm using the password I just set. 
I've tried clearing my browser cache and using a different browser, but the issue persists. 
