package main

import (
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses
	fromAddrParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}

	toAddrParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct properly encoded From header with username
	fromAddress := mail.Address{
		Name:    userName,
		Address: fromAddrParsed.Address,
	}
	encodedFrom := fromAddress.String()
	encodedTo := toAddrParsed.String()

	// Construct and encode subject line
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct HTML body with escaped content to prevent injection and broken markup
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Encode HTML body using quoted-printable for RFC compliance
	var encodedBody strings.Builder
	w := quotedprintable.NewWriter(&encodedBody)
	_, err = w.Write([]byte(htmlBody))
	if err != nil {
		return "", fmt.Errorf("failed to encode body: %w", err)
	}
	if err := w.Close(); err != nil {
		return "", fmt.Errorf("failed to close encoder: %w", err)
	}

	// Construct complete email headers
	headers := fmt.Sprintf(
		"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=UTF-8\r\n"+
			"Content-Transfer-Encoding: quoted-printable\r\n\r\n",
		encodedFrom,
		encodedTo,
		encodedSubject,
	)

	// Combine headers and encoded body
	emailMessage := headers + encodedBody.String()

	return emailMessage, nil
}

