package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation of required fields
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate from address, prepare encoded header value
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	fromHeader := formatAddress(parsedFrom)

	// Parse and validate to address, prepare encoded header value
	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}
	toHeader := formatAddress(parsedTo)

	// Construct email subject prefix
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Build RFC-compliant headers with proper encoding
	var headerStr strings.Builder

	// Encode subject to handle non-ASCII characters
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Write headers in standard order
	fmt.Fprintf(&headerStr, "From: %s\r\n", fromHeader)
	fmt.Fprintf(&headerStr, "To: %s\r\n", toHeader)
	fmt.Fprintf(&headerStr, "Subject: %s\r\n", encodedSubject)
	fmt.Fprintf(&headerStr, "MIME-Version: 1.0\r\n")
	fmt.Fprintf(&headerStr, "Content-Type: text/html; charset=UTF-8\r\n")
	fmt.Fprintf(&headerStr, "Content-Transfer-Encoding: 7bit\r\n")

	// Add blank line separator between headers and body
	headerStr.WriteString("\r\n")

	// Construct HTML body with escaped user inputs to prevent XSS and HTML corruption
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)

	// Replace line endings to comply with RFC 5322
	htmlBodyRFC := strings.ReplaceAll(htmlBody, "\n", "\r\n")

	// Combine headers and formatted HTML body to form complete email
	emailBody = headerStr.String() + htmlBodyRFC

	return emailBody, nil
}

// formatAddress takes a parsed mail.Address and returns an RFC-compliant string
// with encoded display name if it contains non-ASCII characters
func formatAddress(addr *mail.Address) string {
	if addr.Name == "" {
		return addr.Address
	}
	encodedName := mime.QEncoding.Encode("UTF-8", addr.Name)
	return fmt.Sprintf("%s <%s>", encodedName, addr.Address)
}

