	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to remove newline characters, preventing header injection attacks
	sanitizedSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", " "), "\n", " ")

	// Encode subject using RFC 2047 for non-ASCII characters and ensure header compliance
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct email headers with properly formatted addresses and encoded subject
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		parsedFrom.String(),
		parsedTo.String(),
		encodedSubject,
	)

	// HTML-escape all user-provided content to prevent XSS attacks in email clients
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(sanitizedSubject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped user content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
