package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// encodeSubject encodes the email subject according to RFC 2047 for non-ASCII characters
func encodeSubject(subject string) string {
	// Check if subject contains non-ASCII characters
	hasNonASCII := false
	for _, r := range subject {
		if r > 0x7F {
			hasNonASCII = true
			break
		}
	}
	if !hasNonASCII {
		return subject
	}
	// Use quoted-printable encoding for RFC 2047 compliance
	return mime.QEncoding.Encode("UTF-8", subject)
}

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate email addresses, then use properly formatted strings for headers
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct and encode email subject
	fullSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := encodeSubject(fullSubject)

	// Construct email headers with RFC-compliant formatting
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		parsedFrom.String(),
		parsedTo.String(),
		encodedSubject,
	)

	// Escape user input to prevent XSS and invalid HTML
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped user content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 0 auto; padding: 20px; }
    .feedback-section { background-color: #f9f9f9; padding: 15px; border-radius: 5px; border-left: 4px solid #2196F3; }
    .label { font-weight: bold; color: #555; }
    .content { margin-left: 8px; }
  </style>
</head>
<body>
  <h2 style="color: #2196F3;">New User Feedback Received</h2>
  <p><span class="label">Submitted by:</span><span class="content">%s</span></p>
  <p><span class="label">Subject:</span><span class="content">%s</span></p>
  <div class="feedback-section">
    <p class="label">Feedback Message:</p>
    <pre style="white-space: pre-wrap; word-wrap: break-word; margin: 10px 0; padding: 10px; background-color: #fff; border: 1px solid #ddd; border-radius: 3px;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Combine headers and body into final email message
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

